526	func syncWorkTreeToHeadGuarded(gitOps LandingGitOps, dir, fromRev string, dirtyBefore []string, result *LandResult) {
527		overlap, err := checkoutSyncDirtyOverlapPaths(dir, fromRev, dirtyBefore)
528		if err == nil && len(overlap) > 0 {
529			if result != nil {
530				result.CheckoutSyncDeferred = true
531				result.CheckoutSyncDeferredPaths = appendUniqueStrings(result.CheckoutSyncDeferredPaths, overlap...)
532			}
533			_ = syncWorkTreeToHeadExcludingPaths(dir, fromRev, overlap)
534			return
535		}
536		_ = gitOps.SyncWorkTreeToHead(dir, fromRev)
537	}
