580	func checkoutSyncDirtyOverlapPaths(dir, fromRev string, dirtyPaths []string) ([]string, error) {
581		if fromRev == "" || len(dirtyPaths) == 0 {
582			return nil, nil
583		}
584		diffOut, diffErr := internalgit.Command(context.Background(), dir, "diff", "--name-only", fromRev, "HEAD").CombinedOutput()
585		if diffErr != nil {
586			return nil, diffErr
587		}
588		changed := map[string]bool{}
589		for _, path := range strings.Fields(strings.TrimSpace(string(diffOut))) {
590			changed[filepath.ToSlash(path)] = true
591		}
592		if len(changed) == 0 {
593			return nil, nil
594		}
595		var overlap []string
596		for _, path := range dirtyPaths {
597			slashPath := filepath.ToSlash(path)
598			if checkoutSyncDeferralIgnoredPath(slashPath) {
599				continue
600			}
601			if changed[slashPath] {
602				overlap = append(overlap, slashPath)
603			}
604		}
605		return overlap, nil
606	}
607	
608	func checkoutSyncDeferralIgnoredPath(path string) bool {
609		if strings.HasPrefix(path, ".ddx/executions/") ||
610			strings.HasPrefix(path, ".ddx/runs/") ||
611			strings.HasPrefix(path, ".ddx/backups/") ||
612			strings.HasPrefix(path, ".ddx/run-state/") ||
613			strings.HasPrefix(path, ".ddx/.git-tracker.lock/") {
614			return true
615		}
616		return path == ".ddx/run-state.json" || path == ExecutionCleanupMetadataFileName
617	}
