619	func appendUniqueStrings(existing []string, additions ...string) []string {
620		seen := make(map[string]bool, len(existing)+len(additions))
621		for _, value := range existing {
622			seen[value] = true
623		}
624		for _, value := range additions {
625			if seen[value] {
626				continue
627			}
628			seen[value] = true
629			existing = append(existing, value)
630		}
631		return existing
632	}
