657	func (RealLandingGitOps) MergeInto(wtDir, srcRev, msg string) error {
658		// --no-ff forces a merge commit even when the merge could fast-forward
659		// (which shouldn't happen given our caller's ancestry check, but is a
660		// defensive guarantee that target history always gets a marker commit).
661		// We inject user.name/user.email via -c so the merge commit can be
662		// created even when the worktree inherited no git config; the
663		// coordinator is a machine actor and should not adopt a human's identity.
664		out, err := internalgit.Command(
665			context.Background(), wtDir,
666			"-c", "user.name=ddx-land-coordinator",
667			"-c", "user.email=coordinator@ddx.local",
668			"merge", "--no-ff", "-m", msg, srcRev,
669		).CombinedOutput()
670		if err != nil {
671			_ = internalgit.Command(context.Background(), wtDir, "merge", "--abort").Run()
672			return fmt.Errorf("git merge --no-ff %s: %s: %w", srcRev, strings.TrimSpace(string(out)), err)
673		}
674		return nil
675	}
