677	func (RealLandingGitOps) HeadRevAt(dir string) (string, error) {
678		out, err := internalgit.Command(context.Background(), dir, "rev-parse", "HEAD").CombinedOutput()
679		if err != nil {
680			return "", fmt.Errorf("git rev-parse HEAD: %s: %w", strings.TrimSpace(string(out)), err)
681		}
682		return strings.TrimSpace(string(out)), nil
683	}
