685	func (RealLandingGitOps) PushFFOnly(dir, remote, localRef, targetBranch string) error {
686		// Refspec "<local>:<remote>" with no '+' prefix → fast-forward only.
687		refspec := fmt.Sprintf("%s:refs/heads/%s", localRef, targetBranch)
688		out, err := internalgit.Command(context.Background(), dir, "push", remote, refspec).CombinedOutput()
689		if err != nil {
690			return fmt.Errorf("git push %s %s: %s: %w", remote, refspec, strings.TrimSpace(string(out)), err)
691		}
692		return nil
693	}
