710	func (RealLandingGitOps) StageDir(dir, relPath string) error {
711		// Exclude embedded session logs from the evidence commit — tracking
712		// multi-thousand-line .jsonl files caused retry review prompts to
713		// balloon past 2M tokens and crash every provider with n_keep > n_ctx
714		// (ddx-39e27896). manifest.json, result.json, prompt.md, and
715		// usage.json remain tracked for audit; the raw session log lives on
716		// disk, not in git history.
717		args := append([]string{"add", "--", relPath}, EvidenceLandExcludePathspecs()...)
718		out, err := internalgit.Command(context.Background(), dir, args...).CombinedOutput()
719		if err != nil {
720			return fmt.Errorf("git add %s: %s: %w", relPath, strings.TrimSpace(string(out)), err)
721		}
722		return nil
723	}
