754	// DiffNameOnly implements LandingGitOps.DiffNameOnly.
755	func (RealLandingGitOps) DiffNameOnly(dir, base, tip string) ([]string, error) {
756		out, err := internalgit.Command(context.Background(), dir, "diff", "--name-only", base, tip, "--").CombinedOutput()
