863	// landEvidence creates a trailing commit that folds the per-attempt execution
864	// evidence directory into the target branch. Called after the main land (ff or
865	// merge) succeeds and before the push. The evidence commit is a normal child of
866	// result.NewTip — the agent's original commit SHA is not amended.
867	func landEvidence(wd, targetBranch string, req LandRequest, gitOps LandingGitOps, result *LandResult) error {
868		branch, err := gitOps.CurrentBranch(wd)
869		if err != nil {
870			return fmt.Errorf("evidence commit branch check: %w", err)
871		}
872		if branch != targetBranch {
873			return fmt.Errorf("evidence commit branch mismatch: on %q, want %q", branch, targetBranch)
874		}
875		if err := gitOps.StageDir(wd, req.EvidenceDir); err != nil {
876			return fmt.Errorf("stage evidence: %w", err)
877		}
878		msg := fmt.Sprintf("chore: add execution evidence [%s]", shortAttempt(req.AttemptID))
879		sha, err := gitOps.CommitStaged(wd, msg)
880		if err != nil {
881			return fmt.Errorf("commit evidence: %w", err)
882		}
883		if sha == "" {
884			// Evidence already committed in the working tree (worktree-origin path):
885			// the bundle was committed inside the attempt worktree as part of ResultRev
886			// so it is present at HEAD when the landing finalization worktree is checked
887			// out. No trailing commit needed; verify tracked files exist then accept.
888			if !evidenceDirHasTrackedFiles(wd, req.EvidenceDir) {
889				return fmt.Errorf("commit evidence: no staged evidence files under %s", req.EvidenceDir)
890			}
891			headSHA, headErr := gitOps.HeadRevAt(wd)
892			if headErr != nil {
893				return fmt.Errorf("evidence already committed, reading HEAD: %w", headErr)
894			}
895			result.EvidenceCommitSHA = headSHA
896			return nil
897		}
898		result.EvidenceCommitSHA = sha
899		result.NewTip = sha
900		return nil
901	}
