911	func landingFinalizationWorktree(projectRoot, wd, targetBranch string, gitOps LandingGitOps) (string, func(), error) {
912		if !sameFilesystemPath(projectRoot, wd) {
913			return wd, func() {}, nil
914		}
915		tempWT, err := os.MkdirTemp("", "ddx-land-finalize-*")
916		if err != nil {
917			return "", nil, fmt.Errorf("creating landing finalization worktree: %w", err)
918		}
919		_ = os.RemoveAll(tempWT)
920		if err := gitOps.AddBranchWorktree(wd, tempWT, targetBranch); err != nil {
921			_ = os.RemoveAll(tempWT)
922			return "", nil, fmt.Errorf("adding landing finalization worktree for %s: %w", targetBranch, err)
923		}
924		cleanup := func() {
925			_ = gitOps.RemoveWorktree(wd, tempWT)
926			_ = os.RemoveAll(tempWT)
927		}
928		return tempWT, cleanup, nil
929	}
