1340	func largestDeletionFinding(gitOps LandingGitOps, wd, baseRev, resultRev string, threshold int) (largeDeletionFinding, bool, error) {
1341		raw, err := gitOps.DiffNumstat(wd, baseRev, resultRev)
1342		if err != nil {
1343			return largeDeletionFinding{}, false, fmt.Errorf("checking large deletions: %w", err)
1344		}
1345		var largest largeDeletionFinding
1346		for _, line := range strings.Split(strings.TrimSpace(raw), "\n") {
1347			if strings.TrimSpace(line) == "" {
1348				continue
1349			}
1350			parts := strings.SplitN(line, "\t", 3)
1351			if len(parts) != 3 || parts[1] == "-" {
1352				continue
1353			}
1354			deleted, parseErr := strconv.Atoi(parts[1])
1355			if parseErr != nil {
1356				continue
1357			}
1358			if deleted > threshold && deleted > largest.Deleted {
1359				largest = largeDeletionFinding{Path: parts[2], Deleted: deleted}
1360			}
1361		}
1362		return largest, largest.Path != "", nil
1363	}
