1409	func syntaxSanityFindingForResult(gitOps LandingGitOps, wd, baseRev, resultRev string) (syntaxSanityFinding, bool, error) {
1410		paths, err := gitOps.DiffNameOnly(wd, baseRev, resultRev)
1411		if err != nil {
1412			return syntaxSanityFinding{}, false, err
1413		}
1414		for _, path := range paths {
1415			result, ok, err := gitFileAt(wd, resultRev, path)
1416			if err != nil {
1417				return syntaxSanityFinding{}, false, err
1418			}
1419			if !ok {
1420				continue // deleted files are handled by deletion gates, not syntax checks.
1421			}
1422			base, _, err := gitFileAt(wd, baseRev, path)
1423			if err != nil {
1424				return syntaxSanityFinding{}, false, err
1425			}
1426			if reason, bad := syntaxSanityFailure(path, base, result); bad {
1427				return syntaxSanityFinding{Path: path, Reason: reason}, true, nil
1428			}
1429		}
1430		return syntaxSanityFinding{}, false, nil
1431	}
