1433	func gitFileAt(wd, rev, path string) ([]byte, bool, error) {
1434		out, err := internalgit.Command(context.Background(), wd, "show", rev+":"+path).CombinedOutput()
1435		if err != nil {
1436			if strings.Contains(string(out), "does not exist") || strings.Contains(string(out), "exists on disk, but not in") {
1437				return nil, false, nil
1438			}
1439			return nil, false, fmt.Errorf("reading %s at %s: %s: %w", path, rev, strings.TrimSpace(string(out)), err)
1440		}
1441		return out, true, nil
1442	}
1443	
1444	func syntaxSanityFailure(path string, base, result []byte) (string, bool) {
1445		switch strings.ToLower(filepath.Ext(path)) {
1446		case ".json":
1447			var v any
1448			if err := json.Unmarshal(result, &v); err != nil {
1449				return "invalid JSON: " + err.Error(), true
1450			}
1451		case ".go":
1452			if _, err := parser.ParseFile(token.NewFileSet(), path, result, parser.AllErrors); err != nil {
1453				return "invalid Go syntax: " + err.Error(), true
1454			}
1455		case ".svelte":
1456			return svelteSanityFailure(base, result)
1457		}
1458		return "", false
1459	}
