1474	// landPush pushes the new target tip to origin when a remote exists. Push
1475	// failure is non-fatal for the local land outcome; it is surfaced via
1476	// PushFailed/PushError on the result.
1477	//
1478	// On the first push rejection landPush attempts one automatic recovery —
1479	// fetch origin, merge our local tip into the new origin tip, advance the
1480	// local target ref, and retry the push. The race-with-remote case (origin
1481	// advanced with non-overlapping work between our local merge and our push)
1482	// is the common failure in a multi-worker / multi-operator setup and can be
1483	// fixed without operator intervention. If the auto-merge produces a conflict
1484	// the loop cannot resolve, landPush marks the result PushConflict (a distinct
1485	// signal from generic PushFailed) so the caller can park the bead for human
1486	// review under a short cooldown rather than the long park used for
1487	// non-recoverable push failures.
1488	func landPush(wd, targetBranch, newTip string, hasOrigin bool, gitOps LandingGitOps, result *LandResult) {
1489		if !hasOrigin {
1490			return
1491		}
1492		firstErr := gitOps.PushFFOnly(wd, "origin", newTip, targetBranch)
1493		if firstErr == nil {
1494			return
1495		}
1496		// First push rejected. Try one automatic pull/merge/retry-push pass.
1497		if recovered, mergeSHA, recErr := landPushAutoRecover(wd, targetBranch, newTip, gitOps); recovered {
1498			result.NewTip = mergeSHA
1499			result.PushRecovered = true
1500			return
1501		} else if recErr != nil && isPushAutoMergeConflict(recErr) {
1502			// Auto-merge could not be resolved without operator input.
1503			result.PushConflict = true
1504			result.PushError = recErr.Error()
1505			return
1506		}
1507		// Either recovery itself failed for non-conflict reasons (network, auth,
1508		// fetch error, retry push still rejected) or origin was already at our
1509		// tip. Surface the original push error so operator messages match the
1510		// historical contract.
1511		result.PushFailed = true
1512		result.PushError = firstErr.Error()
1513	}
