1591	// LandConflictAutoRecover attempts a 3-way merge of a preserved iteration ref
1592	// onto the current target-branch tip using the ort strategy with -X ours. The
1593	// strategy resolves mechanical conflicts (positional drift from parallel beads)
1594	// by favouring the current tip's version of any conflicting sections while still
1595	// including the preserved iteration's non-conflicting changes in the merge
1596	// commit. If the merge succeeds the local target branch is advanced and the new
1597	// merge commit SHA is returned.
1598	//
1599	// A non-nil error means the ort merge failed (unresolvable content conflict or
1600	// git error) — the caller should escalate to a focused conflict-resolve agent.
1601	// The target branch is never modified on error.
1602	func LandConflictAutoRecover(wd, preserveRef string, gitOps LandingGitOps) (string, error) {
1603		dirtyBefore := dirtyWorktreePaths(wd)
1604		targetBranch, err := gitOps.CurrentBranch(wd)
1605		if err != nil {
1606			return "", fmt.Errorf("resolving target branch: %w", err)
1607		}
1608		targetRef := "refs/heads/" + targetBranch
1609	
1610		currentTip, err := gitOps.ResolveRef(wd, targetRef)
1611		if err != nil {
1612			return "", fmt.Errorf("resolving target tip %s: %w", targetRef, err)
1613		}
1614	
1615		iterSHA, err := gitOps.ResolveRef(wd, preserveRef)
1616		if err != nil {
1617			return "", fmt.Errorf("resolving preserved ref %s: %w", preserveRef, err)
1618		}
1619	
1620		tempWT, mkErr := os.MkdirTemp("", "ddx-conflict-recover-*")
1621		if mkErr != nil {
1622			return "", fmt.Errorf("creating temp worktree: %w", mkErr)
1623		}
1624		_ = os.RemoveAll(tempWT)
1625		if addErr := gitOps.AddWorktree(wd, tempWT, currentTip); addErr != nil {
1626			return "", fmt.Errorf("adding temp worktree at %s: %w", currentTip, addErr)
1627		}
1628		defer func() { _ = gitOps.RemoveWorktree(wd, tempWT) }()
1629	
1630		mergeMsg := fmt.Sprintf("Merge preserved iteration %s after base drift (ort -X ours)", preserveRef)
1631		out, mergeErr := internalgit.Command(
1632			context.Background(), tempWT,
1633			"-c", "user.name=ddx-land-coordinator",
1634			"-c", "user.email=coordinator@ddx.local",
1635			"merge", "--no-ff", "-s", "ort", "-X", "ours", "-m", mergeMsg, iterSHA,
1636		).CombinedOutput()
1637		if mergeErr != nil {
1638			_ = internalgit.Command(context.Background(), tempWT, "merge", "--abort").Run()
1639			return "", fmt.Errorf("ort merge: %s: %w", strings.TrimSpace(string(out)), mergeErr)
1640		}
1641	
1642		mergeSHA, headErr := gitOps.HeadRevAt(tempWT)
1643		if headErr != nil {
1644			return "", fmt.Errorf("reading merge HEAD: %w", headErr)
1645		}
1646		if updErr := gitOps.UpdateRefTo(wd, targetRef, mergeSHA, currentTip); updErr != nil {
1647			return "", fmt.Errorf("advancing %s to %s: %w", targetRef, mergeSHA, updErr)
1648		}
1649		syncWorkTreeToHeadGuarded(gitOps, wd, currentTip, dirtyBefore, nil)

1650		return mergeSHA, nil
1651	}
