	if pushErr := gitOps.PushFFOnly(wd, "origin", mergeSHA, targetBranch); pushErr != nil {
		return false, "", fmt.Errorf("auto-recovery retry push: %w", pushErr)
	}
	return true, mergeSHA, nil
}

