// TestLand_IsNetworkFree verifies that Land() works end-to-end using a
// LandingGitOps implementation that has no fetch or push methods — compile-time
// proof that Land() requires no network I/O.
func TestLand_IsNetworkFree(t *testing.T) {
	// networkFreeOps embeds RealLandingGitOps and satisfies LandingGitOps.
	// Because LandingGitOps no longer declares FetchBranch, PushFFOnly, or
	// FetchOriginAncestryCheck, this struct compiles without any network
	// methods — proving Land() can succeed without them.
	type networkFreeOps struct{ RealLandingGitOps }

	r := newLandTestRepo(t)
	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "content\n", "feat: network-free test")

	land, err := Land(r.dir, LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-network-free",
		AttemptID:    "20260510T000001-nf",
		TargetBranch: "main",
	}, networkFreeOps{})
	if err != nil {
		t.Fatalf("Land with networkFreeOps: %v", err)
	}
	if land.Status != "landed" {
		t.Errorf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
	}
	if land.NewTip != workerSHA {
		t.Errorf("NewTip = %s, want %s (fast-forward path)", land.NewTip, workerSHA)
	}
}

// TestLand_LockReleasedAfterReturn verifies AC #4: withMainGitLock is released
// when Land() returns, not when the caller finishes post-land work.
func TestLand_LockReleasedAfterReturn(t *testing.T) {
	r := newLandTestRepo(t)
	workerSHA := r.commitOn(r.baseSHA, "file.txt", "content\n", "feat: lock-timing test")

	_, err := Land(r.dir, LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-lock-timing",
		AttemptID:    "20260510T000002-lt",
		TargetBranch: "main",
	}, RealLandingGitOps{})
	if err != nil {
		t.Fatalf("Land: %v", err)
	}

	// After Land() returns the lock must be acquirable within 1s, even while
	// the caller performs post-land work (simulated by the 1s deadline itself).
	done := make(chan error, 1)
	go func() {
		done <- withMainGitLock(r.dir, func() error { return nil })
	}()

	select {
	case lockErr := <-done:
		if lockErr != nil {
			t.Fatalf("withMainGitLock after Land: %v", lockErr)
		}
	case <-time.After(time.Second):
		t.Fatal("lock was not released within 1s after Land() returned")
	}
}

